// Extract URL and check for #publish flag
const message = $input.first().json.message?.text || '';
const urlMatch = message.match(/https?:\/\/[^\s]+/);
const hasPublish = message.toLowerCase().includes('#publish');

if (!urlMatch) {
  throw new Error('Không tìm thấy URL trong tin nhắn!');
}

return [{
  json: {
    url: urlMatch[0],
    shouldPublish: hasPublish,
    chatId: $input.first().json.message?.chat?.id,
    originalMessage: message
  }
}];

// Clean HTML to readable text
const html = $input.first().json.data || $input.first().json.body || '';
const prevData = $('Extract URL & Flags').first().json;

// Remove script, style, nav, header, footer, sidebar
let clean = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<aside[\s\S]*?<\/aside>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '');

// Extract title
const titleMatch = clean.match(/<title[^>]*>([^<]*)<\/title>/i);
const ogTitleMatch = clean.match(/property="og:title"\s+content="([^"]*)"/i);
const pageTitle = ogTitleMatch?.[1] || titleMatch?.[1] || 'Untitled';

// Extract cover image
const ogImageMatch = clean.match(/property="og:image"\s+content="([^"]*)"/i);
const coverImage = ogImageMatch?.[1] || '';

// Extract main content
const articleMatch = clean.match(/<article[^>]*>([\s\S]*?)<\/article>/i)
  || clean.match(/<main[^>]*>([\s\S]*?)<\/main>/i)
  || clean.match(/<div[^>]*class="[^"]*content[^"]*"[^>]*>([\s\S]*?)<\/div>/i);

let content = articleMatch ? articleMatch[1] : clean;

// Convert H tags
content = content.replace(/<h[1-6][^>]*>(.*?)<\/h[1-6]>/gi, '\n## $1\n');
// Convert paragraphs
content = content.replace(/<p[^>]*>/gi, '\n').replace(/<\/p>/gi, '\n');
// Convert lists
content = content.replace(/<li[^>]*>/gi, '\n- ').replace(/<\/li>/gi, '');
// Convert br
content = content.replace(/<br\s*\/?>/gi, '\n');
// Remove remaining HTML tags
content = content.replace(/<[^>]+>/g, '');
// Clean up whitespace
content = content.replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Limit content length for AI
const maxChars = 8000;
if (content.length > maxChars) {
  content = content.substring(0, maxChars) + '\n\n[... nội dung đã được cắt bớt]';
}

return [{
  json: {
    pageTitle,
    coverImage,
    rawContent: content,
    url: prevData.url,
    shouldPublish: prevData.shouldPublish,
    chatId: prevData.chatId
  }
}];

// Parse AI Agent response and prepare blog post data
const aiResponse = $input.first().json;
const prevData = $('Clean HTML').first().json;

// AI Agent trả output ở field 'output' hoặc 'text'
const rawOutput = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);

let aiContent;
try {
  // Remove markdown code blocks if present
  const cleaned = rawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiContent = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI trả về không đúng format JSON: ' + e.message + '\nRaw: ' + rawOutput.substring(0, 500));
}

const status = prevData.shouldPublish ? 'published' : 'draft';

return [{
  json: {
    title: aiContent.title || prevData.pageTitle,
    slug: aiContent.slug || prevData.pageTitle.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-'),
    excerpt: aiContent.excerpt || '',
    content: aiContent.content || '',
    cover_image: prevData.coverImage || '',
    category_slug: aiContent.category_slug || 'meo-mua-sam',
    category_name: aiContent.category_name || 'Mẹo mua sắm',
    status: status,
    chatId: prevData.chatId,
    sourceUrl: prevData.url
  }
}];

